<?php require_once __DIR__.'/../app/bootstrap.php'; if(!installed()) redirect('/install/'); $err=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $st=db()->prepare('SELECT * FROM admins WHERE username=?'); $st->execute([$_POST['username']??'']); $u=$st->fetch(); if($u&&password_verify((string)$_POST['password'],$u['password_hash'])){session_regenerate_id(true);$_SESSION['admin_id']=$u['id'];redirect('/admin/');} $err='ログインに失敗しました'; } $site=e(setting('site_name','livedoorアンテナ')); ?><!doctype html><html lang=ja><head><meta charset=utf-8><meta name=viewport content='width=device-width,initial-scale=1'><link rel=stylesheet href='<?=e(app_url('/assets/admin.css'))?>'><title>Login</title></head><body><main style="margin:105px auto 0;max-width:430px;padding:0 12px"><form method=post style="padding:22px 20px"><h1 style="margin:0 0 7px;font-size:20px"><?=$site?></h1><p style="margin:0 0 16px;color:#50575e;font-size:14px">管理画面ログイン</p><?php if($err)echo'<p class="notice error">'.e($err).'</p>';?><label style="font-size:15px;font-weight:700">ユーザー名<input name=username required style="margin-top:6px;margin-bottom:12px"></label><label style="font-size:15px;font-weight:700">パスワード<input type=password name=password required style="margin-top:6px;margin-bottom:14px"></label><button style="width:100%;padding:9px 12px;font-size:14px">ログイン</button></form></main></body></html>
